'use client'

import { createStyleContext } from '../../lib/stalk-ui/create-style-context'
// Stalk UI component - requires PandaCSS setup and @stalk-ui/preset.
import { useVirtualizer } from '@tanstack/react-virtual'
import { createContext, forwardRef, useContext, useMemo, useRef } from 'react'
import { cx } from 'styled-system/css'
import { virtualList as virtualListRecipe } from 'styled-system/recipes'

import type { VirtualItem } from '@tanstack/react-virtual'
import type { CSSProperties, HTMLAttributes, ReactNode } from 'react'

const { StyleProvider, useSlotStyles } = /* @__PURE__ */ createStyleContext(virtualListRecipe, {
  name: 'VirtualList',
})

interface VirtualListContextValue {
  horizontal: boolean
  // TanStack's ref callback: reads `data-index` off the node to record its real size.
  measureElement: (node: Element | null) => void
}

const VirtualListContext = /* @__PURE__ */ createContext<VirtualListContextValue | null>(null)

const useVirtualListContext = (): VirtualListContextValue => {
  const context = useContext(VirtualListContext)
  if (context === null) {
    throw new Error('VirtualList.Item must be rendered inside <VirtualList>.')
  }
  return context
}

export interface VirtualListProps<TItem> extends Omit<HTMLAttributes<HTMLDivElement>, 'children'> {
  /** The full backlog. Only the visible window (plus overscan) is ever in the DOM. */
  items: readonly TItem[]
  /** Estimated item size in px for the flat `index`; refined by real measurement. */
  estimateSize: (index: number) => number
  /** Extra items rendered beyond the viewport to smooth fast scrolls (default 8). */
  overscan?: number
  /** Scroll/lay out along the inline axis instead of the block axis. */
  horizontal?: boolean
  /** Gap in px between items. */
  gap?: number
  /** Stable key for an item; defaults to its flat index. */
  getItemKey?: (item: TItem, index: number) => number | string
  /** Render one item — wrap the return in `<VirtualList.Item>`. */
  children: (item: TItem, virtualItem: VirtualItem) => ReactNode
}

/**
 * Headless windowed list. Renders only the items intersecting the scroll viewport
 * (plus `overscan`), so a 100k-row backlog stays at a handful of DOM nodes. Item
 * heights need not be uniform — pass an `estimateSize` and each rendered
 * `VirtualList.Item` self-measures. Built directly on TanStack Virtual's
 * `useVirtualizer`; no re-wrapping so the escape hatches stay reachable.
 */
export function VirtualListRoot<TItem>({
  items,
  estimateSize,
  overscan = 8,
  horizontal = false,
  gap,
  getItemKey,
  className,
  children,
  ...props
}: VirtualListProps<TItem>) {
  const scrollRef = useRef<HTMLDivElement>(null)
  const virtualizer = useVirtualizer({
    count: items.length,
    getScrollElement: () => scrollRef.current,
    estimateSize,
    overscan,
    horizontal,
    ...(gap === undefined ? {} : { gap }),
    ...(getItemKey
      ? { getItemKey: (index: number) => getItemKey(items[index] as TItem, index) }
      : {}),
  })

  const styles = useMemo(
    () => virtualListRecipe({ orientation: horizontal ? 'horizontal' : 'vertical' }),
    [horizontal],
  )

  const contextValue = useMemo<VirtualListContextValue>(
    () => ({ horizontal, measureElement: virtualizer.measureElement }),
    [horizontal, virtualizer],
  )

  const virtualItems = virtualizer.getVirtualItems()
  const totalSize = virtualizer.getTotalSize()
  const viewportStyle: CSSProperties = horizontal ? { width: totalSize } : { height: totalSize }

  return (
    <StyleProvider value={styles}>
      <VirtualListContext.Provider value={contextValue}>
        <div ref={scrollRef} className={cx(styles.root, className)} {...props}>
          <div className={styles.viewport} style={viewportStyle}>
            {virtualItems.map((virtualItem) => {
              const item = items[virtualItem.index]
              return item === undefined ? null : children(item, virtualItem)
            })}
          </div>
        </div>
      </VirtualListContext.Provider>
    </StyleProvider>
  )
}

export interface VirtualListItemProps extends HTMLAttributes<HTMLDivElement> {
  /** The `VirtualItem` handed to the render callback; positions and measures the row. */
  virtualItem: VirtualItem
}

export const VirtualListItem = /* @__PURE__ */ forwardRef<HTMLDivElement, VirtualListItemProps>(
  function VirtualListItem({ virtualItem, className, style, children, ...props }, ref) {
    const styles = useSlotStyles()
    const { horizontal, measureElement } = useVirtualListContext()

    // The node must reach both TanStack's measurer (for real heights) and any
    // caller-forwarded ref.
    const setRefs = (node: HTMLDivElement | null) => {
      measureElement(node)
      if (typeof ref === 'function') ref(node)
      else if (ref) ref.current = node
    }

    return (
      <div
        ref={setRefs}
        className={cx(styles.item, className)}
        data-index={virtualItem.index}
        style={{
          transform: horizontal
            ? `translateX(${String(virtualItem.start)}px)`
            : `translateY(${String(virtualItem.start)}px)`,
          ...style,
        }}
        {...props}
      >
        {children}
      </div>
    )
  },
)

export const VirtualList = /* @__PURE__ */ Object.assign(VirtualListRoot, {
  Item: VirtualListItem,
  Root: VirtualListRoot,
})

'use client'

import {
  createContext,
  forwardRef,
  useContext,
  type ComponentPropsWithoutRef,
  type ComponentRef,
  type ElementType,
} from 'react'
// Stalk UI component - requires PandaCSS setup and @stalk-ui/preset.

type Slots = Record<string, string>

// Structural shape of a Panda slot recipe, kept deliberately minimal: we only
// rely on the callable (variants -> slot classes) and `splitVariantProps`. The
// variant (`V`) and slot (`S`) types are inferred from the call signature at the
// use site, so they stay precise without restating Panda's generated shape.
//
// `splitVariantProps` is typed loosely on purpose. Its `never` parameter is the
// trick that avoids `any`: because parameters are contravariant, a `never` param
// accepts any recipe's concrete signature — including Panda's generic,
// `DistributiveOmit`-returning one — without the variance clash an exact match
// produces. We never consume its return type (only its first element, re-narrowed
// below), so `unknown` tuple slots are enough.
interface Recipe<V, S extends Slots> {
  (props?: V): S
  splitVariantProps: (props: never) => [unknown, unknown]
}

interface CreateStyleContextOptions {
  name: string
}

const cx = (...classes: (string | false | null | undefined)[]): string => {
  let result = ''
  for (const value of classes) {
    if (typeof value === 'string' && value !== '') {
      if (result !== '') result += ' '
      result += value
    }
  }
  return result
}

const capitalize = (value: string): string =>
  value.length === 0 ? value : value.charAt(0).toUpperCase() + value.slice(1)

export function createStyleContext<V, S extends Slots>(
  recipe: Recipe<V, S>,
  { name }: CreateStyleContextOptions,
) {
  type TSlots = S
  type TVariants = NonNullable<V>

  // `recipe`'s real call/split signatures are erased to `Recipe<V, S>` here; recover
  // the two we actually invoke through contained assertions. This is where the
  // structural looseness above is paid back as precise local types — no `any`.
  const applyRecipe = recipe as unknown as (variantProps: Partial<TVariants>) => TSlots
  const splitVariantProps = recipe.splitVariantProps as (
    props: object,
  ) => [Partial<TVariants>, { className?: string } & Record<string, unknown>]

  const StyleContext = /* @__PURE__ */ createContext<TSlots | null>(null)

  const useSlotStyles = (): TSlots => {
    const styles = useContext(StyleContext)
    if (styles === null) {
      throw new Error(`${name} subcomponents must be rendered inside <${name}Root>.`)
    }
    return styles
  }

  // Escape hatch for roots that need custom rendering (e.g. applying a
  // `colorPalette` from a `tone` prop) while still feeding `withContext` slots.
  // Compute `recipe(variants)` in the root and wrap children in this provider.
  const StyleProvider = StyleContext.Provider

  // Per-part `displayName` so React DevTools shows `AccordionItem` rather than a
  // generic factory name. A factory can't use static function names, so this
  // assignment is the only option — and unlike the top-level mutations the repo
  // rules forbid, it runs inside the `/* @__PURE__ */`-annotated factory call on
  // a freshly created component, so unused parts still tree-shake (verified by
  // scripts/verify-tree-shaking.ts).
  function withRootProvider<TElement extends ElementType>(Component: TElement) {
    type Props = ComponentPropsWithoutRef<TElement> & Partial<TVariants>
    const Styled = /* @__PURE__ */ forwardRef<ComponentRef<TElement>, Props>(
      function StyledRoot(props, ref) {
        const [variantProps, rest] = splitVariantProps(props)
        const styles = applyRecipe(variantProps)
        const { className, ...passthrough } = rest
        const Element: ElementType = Component
        return (
          <StyleContext.Provider value={styles}>
            <Element ref={ref} className={cx(styles.root, className)} {...passthrough} />
          </StyleContext.Provider>
        )
      },
    )
    Styled.displayName = `${name}Root`
    return Styled
  }

  function withContext<TElement extends ElementType>(Component: TElement, slot: keyof TSlots) {
    type Props = ComponentPropsWithoutRef<TElement>
    const slotKey = String(slot)
    const Styled = /* @__PURE__ */ forwardRef<ComponentRef<TElement>, Props>(
      function StyledSlot(props, ref) {
        const styles = useSlotStyles()
        const { className, ...passthrough } = props as {
          className?: string
        } & Record<string, unknown>
        const Element: ElementType = Component
        return <Element ref={ref} className={cx(styles[slotKey], className)} {...passthrough} />
      },
    )
    Styled.displayName = `${name}${capitalize(slotKey)}`
    return Styled
  }

  return { StyleProvider, useSlotStyles, withContext, withRootProvider }
}
